import React, { useState, useEffect } from 'react';
import { useParams } from 'react-router-dom';
import axios from 'axios';
import ArtisanCard from '../components/ArtisanCard';

const CategoryList = () => {
    const { categoryName } = useParams();
    const [artisans, setArtisans] = useState([]);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        setLoading(true);
        const url = `http://localhost:5000/api/artisans/search?q=${categoryName}`;

        axios.get(url)
            .then(res => {
                setArtisans(res.data);
                setLoading(false);
            })
            .catch(err => {
                console.error("Le serveur ne répond pas :", err);
                setLoading(false);
            });
    }, [categoryName]);

    return (
        <div className="container py-5">
            <h2 className="fw-bold mb-5" style={{ color: '#004a99' }}>Artisans : {categoryName}</h2>
            {loading ? (
                <p>Chargement...</p>
            ) : (
                <div className="row g-4">
                    {artisans.length > 0 ? (
                        artisans.map(a => <ArtisanCard key={a.id} artisan={a} />)
                    ) : (
                        <p>Aucun résultat pour "{categoryName}".</p>
                    )}
                </div>
            )}
        </div>
    );
};

export default CategoryList;
